script:
function setupForm(ctx) {
  const { doc, call, createToast } = ctx;

  // Helper function to normalize phone number
  function normalizePhoneNumber(phone) {
    if (!phone) return '';
    return phone.toString().trim();
  }

  // Helper function to get contact phone number
  async function getContactPhone() {
    if (doc.contact) {
      const phone = doc.contact.phone || doc.contact.mobile_no;
      if (phone) {
        return {
          phone: normalizePhoneNumber(phone),
          name: doc.contact.name || doc.contact.full_name || ''
        };
      }
    }

    try {
      const result = await call('justcall_integration.api.get_ticket_contact_phone', {
        ticket_id: doc.name
      });
      return {
        phone: normalizePhoneNumber(result?.phone),
        name: result?.contact_name || ''
      };
    } catch (e) {
      return { phone: null, name: '' };
    }
  }

  // Open JustCall dialer in new tab with metadata
  async function openJustCallDialer() {
    const contactInfo = await getContactPhone();

    if (!contactInfo.phone) {
      createToast({
        title: 'No phone number',
        message: 'This ticket does not have a contact with a phone number.',
        appearance: 'warning',
      });
      return;
    }

    const metadata = {
      ticket_id: doc.name,
      contact: contactInfo.name || doc.contact?.name || '',
      subject: doc.subject || '',
    };

    const baseUrl = 'https://app.justcall.io/dialer';
    const params = new URLSearchParams();
    params.append('numbers', contactInfo.phone);
    params.append('medium', 'custom');
    params.append('metadata', JSON.stringify(metadata));
    params.append('metadata_type', 'json');

    const dialerUrl = `${baseUrl}?${params.toString()}`;
    window.open(dialerUrl, '_blank');
  }

  // Open JustCall dialer without metadata (standby mode)
  function openJustCallStandby() {
    window.open('https://app.justcall.io/dialer', '_blank');
    createToast({
      title: 'JustCall Standby',
      message: 'JustCall dialer opened. You are now on standby for incoming calls.',
      appearance: 'info',
    });
  }

  // Open modal to link calls to this ticket
  async function openLinkCallsModal() {
    try {
      const calls = await call('justcall_integration.api.get_calls_without_ticket');

      if (!calls || calls.length === 0) {
        createToast({
          title: 'No Unlinked Calls',
          message: 'There are no call logs waiting to be linked to this ticket.',
          appearance: 'info',
        });
        return;
      }

      // Track selected calls
      let selectedCalls = [];

      // Remove existing modal if any
      const existingModal = document.getElementById('jc-link-modal');
      if (existingModal) {
        existingModal.remove();
      }

      // Create modal overlay - single layer, no nested overlays
      const overlay = document.createElement('div');
      overlay.id = 'jc-link-modal';
      overlay.style.cssText = 'position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.5); z-index: 10000; display: flex; align-items: center; justify-content: center; font-family: inherit;';

      // Build table rows HTML
      let tableRowsHtml = calls.map((call) => {
        const typeColor = call.type === 'Incoming' ? '#28a745' : '#007bff';
        const hasRecording = call.recording_url && call.recording_url.length > 0;

        return `<tr style="border-bottom: 1px solid #f0f0f0;">
            <td style="padding: 10px; text-align: center;"><input type="checkbox" class="jc-call-cb" data-name="${call.name}" style="cursor: pointer; width: 16px; height: 16px;"></td>
            <td style="padding: 10px; font-size: 13px;">${call.from || '-'}</td>
            <td style="padding: 10px; font-size: 13px;">${call.to || '-'}</td>
            <td style="padding: 10px; font-size: 13px; color: ${typeColor}; font-weight: 500;">${call.type}</td>
            <td style="padding: 10px; font-size: 13px;">${call.status}</td>
            <td style="padding: 10px; font-size: 13px;">${call.duration_formatted || '0s'}</td>
            <td style="padding: 10px; font-size: 13px;">${hasRecording ? `<a href="${call.recording_url}" target="_blank" style="color: #007bff; text-decoration: none;">▶ Play</a>` : '-'}</td>
          </tr>`;
      }).join('');

      // Modal content HTML
      overlay.innerHTML = `
        <div id="jc-modal-box" style="background: white; border-radius: 8px; width: 90%; max-width: 1000px; max-height: 80vh; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.3); display: flex; flex-direction: column;">
          <div style="padding: 20px; border-bottom: 1px solid #e5e5e5; display: flex; justify-content: space-between; align-items: center; flex-shrink: 0;">
            <h3 style="margin: 0; font-size: 16px; font-weight: 600;">Link Call Log to Ticket ${doc.name}</h3>
            <button id="jc-close-btn" style="background: none; border: none; font-size: 24px; cursor: pointer; color: #666; padding: 0; width: 32px; height: 32px; display: flex; align-items: center; justify-content: center; border-radius: 4px;">&times;</button>
          </div>
          <div style="padding: 20px; overflow-y: auto; flex: 1;">
            <p style="margin: 0 0 15px 0; color: #666; font-size: 14px;">Found ${calls.length} call(s) without linked ticket. Select calls to link:</p>
            <table style="width: 100%; border-collapse: collapse;">
              <thead style="background: #f7f7f7;">
                <tr>
                  <th style="padding: 10px; text-align: center; border-bottom: 1px solid #e5e5e5; width: 50px;"><input type="checkbox" id="jc-select-all" style="cursor: pointer; width: 16px; height: 16px;"></th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5; font-size: 13px; font-weight: 600;">From</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5; font-size: 13px; font-weight: 600;">To</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5; font-size: 13px; font-weight: 600;">Type</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5; font-size: 13px; font-weight: 600;">Status</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5; font-size: 13px; font-weight: 600;">Duration</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5; font-size: 13px; font-weight: 600;">Recording</th>
                </tr>
              </thead>
              <tbody>${tableRowsHtml}</tbody>
            </table>
          </div>
          <div style="display: flex; justify-content: flex-end; padding: 20px; border-top: 1px solid #e5e5e5; flex-shrink: 0;">
            <button id="jc-link-btn" style="background: #171717; color: white; border: none; padding: 10px 24px; border-radius: 6px; cursor: pointer; font-size: 14px; font-weight: 500;">Link to this ticket</button>
          </div>
        </div>
      `;

      document.body.appendChild(overlay);

      // Close handlers
      const closeModal = () => overlay.remove();
      document.getElementById('jc-close-btn').addEventListener('click', closeModal);

      // Close on overlay click (but not when clicking modal content)
      overlay.addEventListener('click', (e) => {
        if (e.target === overlay) closeModal();
      });

      // Select all handler
      document.getElementById('jc-select-all').addEventListener('change', (e) => {
        const checkboxes = overlay.querySelectorAll('.jc-call-cb');
        selectedCalls = [];
        checkboxes.forEach(cb => {
          cb.checked = e.target.checked;
          if (e.target.checked) selectedCalls.push(cb.dataset.name);
        });
      });

      // Individual checkbox handlers - use click instead of change for better reliability
      overlay.querySelectorAll('.jc-call-cb').forEach(cb => {
        cb.addEventListener('click', (e) => {
          e.stopPropagation();
          const name = e.target.dataset.name;
          if (e.target.checked) {
            if (!selectedCalls.includes(name)) selectedCalls.push(name);
          } else {
            const idx = selectedCalls.indexOf(name);
            if (idx > -1) selectedCalls.splice(idx, 1);
          }
          // Uncheck "select all" if any item is unchecked
          const selectAll = document.getElementById('jc-select-all');
          if (!e.target.checked && selectAll.checked) selectAll.checked = false;
        });
      });

      // Link button handler
      document.getElementById('jc-link-btn').addEventListener('click', async () => {
        if (selectedCalls.length === 0) {
          createToast({
            title: 'No Calls Selected',
            message: 'Please select at least one call to link.',
            appearance: 'warning',
          });
          return;
        }

        const btn = document.getElementById('jc-link-btn');
        btn.disabled = true;
        btn.textContent = 'Linking...';

        try {
          const result = await call('justcall_integration.api.link_calls_to_ticket', {
            ticket_id: doc.name,
            call_log_names: selectedCalls
          });

          if (result.success) {
            createToast({
              title: 'Success',
              message: `Linked ${result.linked_count} call(s) to this ticket.`,
              appearance: 'success',
            });
            closeModal();
            // Refresh the page to show linked calls
            setTimeout(() => window.location.reload(), 1000);
          } else {
            createToast({
              title: 'Error',
              message: result.message || 'Failed to link calls.',
              appearance: 'error',
            });
            btn.disabled = false;
            btn.textContent = 'Link to this ticket';
          }
        } catch (err) {
          createToast({
            title: 'Error',
            message: 'Failed to link calls. Please try again.',
            appearance: 'error',
          });
          btn.disabled = false;
          btn.textContent = 'Link to this ticket';
        }
      });

    } catch (e) {
      createToast({
        title: 'Error',
        message: 'Failed to open modal. Please try again.',
        appearance: 'error',
      });
    }
  }

  // Return actions
  return {
    actions: [
      {
        label: 'Call via JustCall',
        onClick: openJustCallDialer,
        variant: 'solid',
        theme: 'blue',
      },
      {
        label: 'Standby via JustCall',
        onClick: openJustCallStandby,
        variant: 'outline',
        theme: 'gray',
      },
      {
        group: 'JustCall',
        hideLabel: true,
        items: [
          {
            label: 'Link Call Log to this Ticket',
            onClick: openLinkCallsModal,
          },
        ],
      },
    ]
  };
}
